import (
    "github.com/openmeterio/openmeter/pkg/models"
)

// Build a validation error with a nested field path and custom attribute
func validateAmount(amount float64) error {
    if amount <= 0 {
        return models.NewValidationError("invalid_amount", "amount must be positive").
            WithPathString("lineItems", "amount").
            WithAttr(httpStatusCodeAttr, 422)
    }
    return nil
}

// In HTTP handler, convert to API response
if validationIssues, err := models.AsValidationIssues(err); err == nil {
    problem := models.NewStatusProblem(ctx, err, http.StatusUnprocessableEntity)
    problem.Extensions = map[string]interface{}{
        "validationErrors": validationIssues.AsErrorExtensions(),
    }
    problem.Respond(w)
}

